
import openpyxl as xl
from openpyxl.styles import Font,Alignment,PatternFill,Border,Side
from openpyxl.utils import get_column_letter as gcl
wb=xl.Workbook()
ws=wb.active
ws.title='TestCases'
H=['Test Case#','Test Title / Scenario','Test Summary','Test Steps','Test Data','Expected Result','Post-condition']
W=[14,32,38,55,42,42,40]
hfill=PatternFill('solid',fgColor='1F4E79')
hfont=Font(bold=True,color='FFFFFF',size=10)
t=Side(style='thin')
bd=Border(left=t,right=t,top=t,bottom=t)
al=Alignment(wrap_text=True,vertical='top')
for i,v in enumerate(H,1):
    c=ws.cell(1,i,v);c.font=hfont;c.fill=hfill;c.alignment=al;c.border=bd
    ws.column_dimensions[gcl(i)].width=W[i-1]
ws.row_dimensions[1].height=30
fills=[PatternFill('solid',fgColor=x) for x in ['EBF3FB','D6E4F0','EBF3FB','D6E4F0','EBF3FB','D6E4F0','EBF3FB','D6E4F0','EBF3FB','D6E4F0']]
def row(r,tc,title,smry,steps,data,exp,post,ridx):
    vals=[tc,title,smry,steps,data,exp,post]
    f=fills[ridx%10]
    for i,v in enumerate(vals,1):
        c=ws.cell(r,i,v);c.alignment=al;c.border=bd;c.fill=f
    ws.row_dimensions[r].height=80


